#include <iostream>\n#include <vector>\n#include <deque>\n\nclass Graph {\n public:\n  Graph(size_t n, std::pair<int, int>* edges, size_t m) {\n    // table_.resize(n + 1);\n    n_ = n + 1;\n    table_ = new std::vector<size_t>[n_];\n    tin_ = new size_t[n_]{};\n    tout_ = new size_t[n_]{};\n    // tin_.resize(n + 1, 0);\n    // tout_.resize(n + 1, 0);\n    Build(edges, m);\n  }\n\n  ~Graph() {\n    delete[] tin_;\n    delete[] tout_;\n    delete[] table_;\n  }\n\n  const std::deque<size_t>& FindCycle() {\n    for (size_t i = 1; i < n_; i++) {\n      if (found_cycle_) {\n        return cycle_;\n      }\n      if (GetColor(i) == Colors_::White) {\n        Dfs(i);\n      }\n    }\n    return cycle_;\n  }\n\n private:\n  void Build(std::pair<int, int>* edges, size_t m) {\n    for (size_t it = 0; it < m; it++) {\n      int i = edges[it].first;\n      int j = edges[it].second;\n      table_[i].push_back(j);\n    }\n  }\n\n  void Dfs(size_t start) {\n    cycle_.push_back(start);\n    tin_[start] = time_++;\n    if (found_cycle_) {\n      return;\n    }\n    const std::vector<size_t>& children = table_[start];\n    for (auto i : children) {\n      switch (GetColor(i)) {\n        case Colors_::White:\n          Dfs(i);\n          break;\n        case Colors_::Gray:\n          while (!cycle_.empty() && cycle_.front() != i) {\n            cycle_.pop_front();\n          }\n          found_cycle_ = true;\n          return;\n        case Colors_::Black:\n          break;\n      }\n      if (found_cycle_) {\n        return;\n      }\n    }\n    cycle_.pop_back();\n    tout_[start] = time_++;\n  }\n\n  enum class Colors_;\n  Colors_ GetColor(size_t start) {\n    if (tin_[start] == 0) {\n      return Colors_::White;\n    }\n    if (tout_[start] == 0) {\n      return Colors_::Gray;\n    }\n    return Colors_::Black;\n  }\n\n  size_t time_ = 1;\n  // std::vector<std::vector<size_t>> table_;\n  size_t n_;\n  std::vector<size_t>* table_;\n  std::deque<size_t> cycle_;\n  bool found_cycle_ = false;\n  size_t* tin_;\n  size_t* tout_;\n  // std::vector<size_t> tin_;\n  // std::vector<size_t> tout_;\n  enum class Colors_ { White, Gray, Black };\n};\n\nint main() {\n\n  std::ios_base::sync_with_stdio(false);\n  std::cin.tie(nullptr);\n  std::cout.tie(nullptr);\n\n  size_t n = 0;\n  size_t m = 0;\n  std::cin >> n >> m;\n  auto edges = new std::pair<int, int>[m];\n  // std::vector<std::pair<int, int>> edges(m);\n  for (size_t it = 0; it < m; it++) {\n    int i = 0;\n    int j = 0;\n    std::cin >> i >> j;\n    edges[it] = {i, j};\n  }\n\n  Graph graph(n, edges, m);\n  delete[] edges;\n  std::deque<size_t> nodes = graph.FindCycle();\n\n  if (nodes.empty()) {\n    std::cout << \"NO\\n\";\n  } else {\n    std::cout << \"YES\\n\";\n    while (!nodes.empty()) {\n      std::cout << nodes.front() << ' ';\n      nodes.pop_front();\n    }\n    std::cout << '\\n';\n  }\n  return 0;\n}